module sr_flip_flop (
    input wire S,
    input wire R,
    input wire clk,
    input wire reset,
    output reg Q,
    output reg Qn
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
        if (reset) begin
            Q <= 0;
            Qn <= 1;
        end else begin
            if (S && !R) begin
                Q <= 1;
                Qn <= 0;
            end else if (!S && R) begin
                Q <= 0;
                Qn <= 1;
            end
        end
    end
endmodule
